char* nextTerm(char* s) {
    int len = strlen(s);
    char* res = (char*)malloc(1000000 * sizeof(char)); // very large buffer
    int k = 0, count = 1;

    for (int i = 0; i < len; i++) {
        if (i + 1 < len && s[i] == s[i + 1]) {
            count++;
        } else {
            k += sprintf(res + k, "%d", count);
            res[k++] = s[i];
            count = 1;
        }
    }
    res[k] = '\0';
    return res;
}

// Recursive count-and-say (very slow for n > 20)
char* countAndSay(int n) {
    if (n == 1) {
        char* base = (char*)malloc(2 * sizeof(char));
        strcpy(base, "1");
        return base;
    }
    char* prev = countAndSay(n - 1); // recursively calculate previous term
    char* curr = nextTerm(prev);     // generate current term
    free(prev);                       // free previous term
    return curr;
}

