function nextTerm(s) {
    let res = '';
    let count = 1;
    for (let i = 0; i < s.length; i++) {
        if (i + 1 < s.length && s[i] === s[i + 1]) {
            count++;
        } else {
            res += count.toString() + s[i];
            count = 1;
        }
    }
    return res;
}

// Recursive count-and-say (TLE for large n)
function countAndSay(n) {
    if (n === 1) return "1";
    let prev = countAndSay(n - 1);
    return nextTerm(prev);
}
